module automatic Target(input reg clk_i);
  
   logic [31:0]         mem_data; 
   byte 		data_in[4];
   byte 		data_out[4];
   
   initial begin 
      foreach(data_in[i])  data_in[i] = i+1;
      mem_data =  {<<8{data_in}};
      $display("TEST: mem_data=%h",mem_data );
      {<<byte{data_out}} = mem_data;
      foreach(data_out[i])  $display("TEST: data_out[%0d]=%h",i,data_out[i]);
   end

endmodule
